import { Component, Prop, Element, h, State, EventEmitter, Event, Host, Listen } from '@stencil/core';

import { generateRandId } from '../../utils/utils';
import { KEYBOARD_KEYS } from '../../models/keycodes.model';
import { getIconClass, getBaseClasses, getDisabledClasses, getDefaultClasses, getCustomIconClass, getPrimaryLabelClasses, getSecondaryLabelClasses } from './tile-utils';
import { TileBackgroundIcon, TileOrientation, TileVisualContent } from './wdpr-tile.model';
import { StringBoolean } from '../wdpr-text-area/wdpr-text-field.model';

@Component({
  tag: 'wdpr-tile',
  shadow: true,
  styleUrl: 'wdpr-tile.css',
})
export class WdprTile {
  @Element() el!: HTMLWdprTileElement;

  @State() _hasAvatarGroup: boolean = false;
  @State() _internalId!: string;

  @Prop() label: string = '';
  @Prop({ reflect: true, mutable: true }) disabled: boolean = false;
  @Prop() visualContent: TileVisualContent = 'icon';
  @Prop() roleType?: 'button' | 'link' = 'button';
  @Prop({ reflect: true }) iconJustified: boolean = false;
  @Prop() secondaryLabel?: string | null = null;
  @Prop() iconName?: string;
  @Prop() mediaSrc?: string;
  @Prop() orientation: TileOrientation = 'vertical';
  @Prop() fullWidth?: StringBoolean | boolean = 'false';
  @Prop() backgroundIcon: TileBackgroundIcon = 'none';
  @Prop() tileId?: string;
  @Prop() showNotificationIcon?: boolean = false;
  @Prop() navigationPath?: string = '';

  @Prop({ attribute: 'a11y-label' }) a11yLabel: string = '';
  @Prop({ attribute: 'a11y-icon-label' }) a11yIconLabel?: string;

  @Event({ eventName: 'wdprClick' }) wdprClick!: EventEmitter<{ tileElement: unknown; navigationPath?: string }>;

  componentWillLoad() {
    this._hasAvatarGroup = !!this.el.querySelector('[slot="avatar-group"]');
    this._internalId = this.tileId || `wdpr-tile-${generateRandId()}`;
  }

  @Listen('keydown')
  handleKeyDown(ev: KeyboardEvent) {
    if (ev.key == KEYBOARD_KEYS.ESCAPE) {
      ev.preventDefault();
      (document.activeElement as HTMLElement)?.blur();
    }
  }

  get _baseClasses() {
    return getBaseClasses(this.orientation, this._hasAvatarGroup, this.iconJustified);
  }

  get _disabledClasses() {
    return getDisabledClasses(this._baseClasses);
  }

  get _defaultClasses() {
    return getDefaultClasses(this._baseClasses, this.orientation, this.backgroundIcon, !!this.secondaryLabel);
  }

  get _customClass() {
    return getCustomIconClass(this.disabled, this.backgroundIcon);
  }

  get _iconClass() {
    return getIconClass(this.disabled);
  }

  private _onPress = () => {
    if (this.disabled) return;

    this.wdprClick.emit({ tileElement: this.el, navigationPath: this.navigationPath });
  };

  private _onKeyDown = (event: KeyboardEvent) => {
    const key = event.key;

    if (key == KEYBOARD_KEYS.ENTER || (key == KEYBOARD_KEYS.SPACE && this.roleType !== 'link')) {
      event.preventDefault();
      this._onPress();
    }
  };

  render() {
    const isLink = this.roleType === 'link' && !!this.navigationPath;
    const Tag = this.roleType === 'link' ? 'a' : 'div';
    const linkProps = isLink ? { href: this.navigationPath } : {};

    return (
      <Host class={{ 'full-width': this.fullWidth == 'true' || this.fullWidth === true }}>
        {this.showNotificationIcon && <wdpr-notification-indicator class="absolute top-[-8] right-[-2]" />}

        <Tag
          {...linkProps}
          class={this.disabled ? this._disabledClasses : this._defaultClasses}
          role={this.roleType === 'button' ? 'button' : undefined}
          tabindex={this.disabled ? -1 : 0}
          aria-disabled={this.disabled ? 'true' : undefined}
          aria-label={this.a11yLabel || undefined}
          id={this._internalId}
          onClick={this._onPress}
          onKeyDown={this._onKeyDown}
        >
          {/* Render icon based on visualConten prop */}
          {this.visualContent === 'icon' && (
            <div class={this._iconClass}>
              {/* vertical orientation uses wdpr-icon-library */}
              {this.orientation === 'vertical' && <wdpr-icon-library icon={this.iconName} size="large" decorative={!this.a11yIconLabel} a11yLabel={this.a11yIconLabel} />}

              {/* horizontal orientation uses wdpr-icon with background options */}
              {this.orientation === 'horizontal' && (
                <wdpr-icon
                  icon={this.iconName}
                  size="medium"
                  background={this.backgroundIcon}
                  variant="secondary"
                  customClass={this._customClass}
                  decorative={!this.a11yIconLabel}
                  a11yLabel={this.a11yIconLabel}
                />
              )}
            </div>
          )}

          {/* Render media based on visualContent prop */}
          {this.visualContent === 'media' && (
            <div class="w-dimension-400 h-dimension-400">
              <wdpr-media src={this.mediaSrc} alt="alt" fade={true} aspect="square" shape="flat" objectFit="fill" landscapeRatio="16:9" portraitRatio="3:4" />
            </div>
          )}

          {/* Render avatar group if it exists */}
          {this.visualContent == 'avatarGroup' && this.orientation === 'vertical' && (
            <div class="ml-[-5px]">
              <slot name="avatar-group" />
            </div>
          )}

          <div class="content-wrapper overflow-hidden text-ellipsis">
            {/* Render primary label */}
            {this.label && <div class={getPrimaryLabelClasses(this.disabled)}>{this.label}</div>}

            {/* Render secondary label if it exists */}
            {this.secondaryLabel && <div class={getSecondaryLabelClasses(this.disabled)}>{this.secondaryLabel}</div>}
          </div>
        </Tag>
      </Host>
    );
  }
}
